using namespace std;

long long solve(long long n, long long k) {
    if (k == 0) return 0;
    if (k == 1) {
        // Numbers with popcount-depth 1 are those with exactly 1 bit set
        // and their popcount is 1, which is the first step to reach 1
        long long count = 0;
        for (long long i = 0; i < 60; ++i) {
            long long power = 1LL << i;
            if (power <= n) count++;
        }
